// ── LOGO INJECTION ──
  const LOGO_DATA = "data:image/png;base64,";
  document.querySelectorAll('img[src="LOGO_PLACEHOLDER"]').forEach(img => {
    img.src = LOGO_DATA;
  });

  // ── DISABLE RIGHT CLICK & SHORTCUTS ──
  document.addEventListener("contextmenu", e => e.preventDefault());
  document.addEventListener("dragstart", e => e.preventDefault());
  document.addEventListener("keydown", e => {
    if ((e.ctrlKey || e.metaKey) && ["s","u","p","i","j"].includes(e.key.toLowerCase())) e.preventDefault();
    if ((e.ctrlKey || e.metaKey) && e.shiftKey && ["i","j","c"].includes(e.key.toLowerCase())) e.preventDefault();
    if (e.key === "F12") e.preventDefault();
  });

  // ── NAV SCROLL ──
  const nav = document.getElementById("main-nav");
  window.addEventListener("scroll", () => {
    nav.classList.toggle("scrolled", window.scrollY > 40);
  });

  // ── MOBILE MENU ──
  const hamburger = document.getElementById("hamburger");
  const mobileMenu = document.getElementById("mobile-menu");
  hamburger.addEventListener("click", () => {
    mobileMenu.classList.toggle("open");
  });
  function closeMobileMenu() {
    mobileMenu.classList.remove("open");
  }

  // ── SCROLL REVEAL ──
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add("visible");
      }
    });
  }, { threshold: 0.1, rootMargin: "0px 0px -40px 0px" });
  document.querySelectorAll(".reveal").forEach(el => observer.observe(el));

  // ── WORKS FILTER ──
  const filterBtns = document.querySelectorAll(".filter-btn");
  const workItems = document.querySelectorAll(".work-item");
  filterBtns.forEach(btn => {
    btn.addEventListener("click", () => {
      filterBtns.forEach(b => b.classList.remove("active"));
      btn.classList.add("active");
      const filter = btn.dataset.filter;
      workItems.forEach(item => {
        if (filter === "all" || item.dataset.cat === filter) {
          item.style.display = "block";
          item.style.opacity = "1";
        } else {
          item.style.display = "none";
        }
      });
    });
  });

  // ── FAQ ──
  document.querySelectorAll(".faq-q").forEach(q => {
    q.addEventListener("click", () => {
      const item = q.parentElement;
      const isOpen = item.classList.contains("open");
      document.querySelectorAll(".faq-item").forEach(i => i.classList.remove("open"));
      if (!isOpen) item.classList.add("open");
    });
  });

  // ── CONTACT FORM ──
  const form = document.getElementById("contact-form");
  const successMsg = document.getElementById("form-success");
  if (form) {
    form.addEventListener("submit", async (e) => {
      e.preventDefault();
      const btn = form.querySelector(".form-submit");
      btn.textContent = "傳送中...";
      btn.disabled = true;
      try {
        const res = await fetch(form.action, {
          method: "POST",
          body: new FormData(form),
          headers: { Accept: "application/json" }
        });
        if (res.ok) {
          form.style.display = "none";
          successMsg.style.display = "block";
        } else {
          btn.textContent = "發送失敗，請重試";
          btn.disabled = false;
        }
      } catch {
        btn.textContent = "發送失敗，請重試";
        btn.disabled = false;
      }
    });
  }

// ── CONTENT PROTECTION ──
(function () {
  const stop = function (event) {
    event.preventDefault();
    event.stopPropagation();
    return false;
  };

  ['contextmenu', 'dragstart', 'selectstart', 'copy', 'cut'].forEach(function (type) {
    document.addEventListener(type, stop, { capture: true });
  });

  document.addEventListener('keydown', function (event) {
    const key = (event.key || '').toLowerCase();
    const blocked =
      key === 'f12' ||
      (event.ctrlKey && event.shiftKey && ['i', 'j', 'c'].includes(key)) ||
      (event.metaKey && event.altKey && ['i', 'j', 'c'].includes(key)) ||
      ((event.ctrlKey || event.metaKey) && ['s', 'u', 'p', 'c', 'x'].includes(key));

    if (blocked) stop(event);
  }, { capture: true });

  document.querySelectorAll('img, svg, video, canvas').forEach(function (el) {
    el.setAttribute('draggable', 'false');
    el.addEventListener('contextmenu', stop, { capture: true });
    el.addEventListener('dragstart', stop, { capture: true });
  });
})();


// ── EXTRA CONTENT PROTECTION ──
(function(){
  document.addEventListener('contextmenu', function(e){ e.preventDefault(); }, {capture:true});
  document.addEventListener('dragstart', function(e){ e.preventDefault(); }, {capture:true});
  document.addEventListener('selectstart', function(e){
    const tag = (e.target && e.target.tagName || '').toLowerCase();
    if (!['input','textarea','select','option'].includes(tag)) e.preventDefault();
  }, {capture:true});
  document.addEventListener('keydown', function(e){
    const key = (e.key || '').toLowerCase();
    if ((e.ctrlKey || e.metaKey) && ['s','u','p','c','x','a'].includes(key)) e.preventDefault();
    if (key === 'f12' || ((e.ctrlKey || e.metaKey) && e.shiftKey && ['i','j','c'].includes(key))) e.preventDefault();
  }, {capture:true});
})();
